// Gets all the possible horizontal moves for a rook on the given square.
inline U64 get_rook_horizontal(Square square, U64 occupancies) {
    return HORIZONTAL[square][_pext_u64(occupancies, HORIZONTAL_MASK[square])];
}

// Gets all the possible vertical moves for a rook on the given square.
inline U64 get_rook_vertical(Square square, U64 occupancies) {
    return VERTICAL[square][_pext_u64(occupancies, VERTICAL_MASK[square])];
}

// Gets all the possible diagonal moves for a bishop on the given square.
inline U64 get_bishop_diagonal(Square square, U64 occupancies) {
    return DIAGONAL[square][_pext_u64(occupancies, DIAGONAL_MASK[square])];
}

// Gets all the possible antidiagonal moves for a bishop on the given square.
inline U64 get_bishop_antidiagonal(Square square, U64 occupancies) {
    return ANTIDIAGONAL[square][_pext_u64(occupancies, ANTIDIAGONAL_MASK[square])];
}

// Gets all the possible moves for a rook on the given square.
inline U64 get_rook_attacks(Square square, U64 occupancies) {
    return get_rook_horizontal(square, occupancies) | get_rook_vertical(square, occupancies);
}

// Gets all the possible moves for a bishop on the given square.
inline U64 get_bishop_attacks(Square square, U64 occupancies){
    return get_bishop_diagonal(square, occupancies) | get_bishop_antidiagonal(square, occupancies);
}

// Gets all the possible moves for a queen on the given square.
inline U64 get_queen_attacks(Square square, U64 occupancies){
    return get_rook_attacks(square, occupancies) | get_bishop_attacks(square, occupancies);
}

inline U64 get_xray_rook_attacks(Square square, U64 occupancies){
    U64 attacks = get_rook_attacks(square, occupancies);
    return attacks ^ get_rook_attacks(square, occupancies ^ (attacks & occupancies));
}

U64 get_xray_bishop_attacks(Square square, U64 occupancies){
    U64 attacks = get_bishop_attacks(square, occupancies);
    return attacks ^ get_bishop_attacks(square, occupancies ^ (attacks & occupancies));
}
